const rows = $input.all().map(item => item.json);

function hasValue(v) {
  return v !== null && v !== undefined && v !== '';
}

function parseQuality(row) {
  if (!row.data_quality) return {};
  if (typeof row.data_quality === 'object') return row.data_quality;
  try {
    return JSON.parse(row.data_quality);
  } catch {
    return {};
  }
}

function isUsableUsdSnapshot(row) {
  if (!row.snapshot_date || !row.run_time_et) return false;

  const required = [
    'vix_level',
    'dxy_level',
    'dxy_d1',
    'dxy_d5',
    'us_2y_yield',
    'us_2y_d5_bps',
    'de_2y_yield',
    'us_de_2y_spread',
    'us_de_2y_spread_d5_bps',
    'us_10y_real_yield',
    'us_10y_real_yield_d5_bps',
    'gold_d1_pct',
    'nq_d1_pct',
    'fed_bias'
  ];

  return required.every(key => hasValue(row[key]));
}

const sortedRows = rows
  .filter(r => r.snapshot_date && r.run_time_et)
  .sort((a, b) => {
    const bTime = new Date(b.run_time_et || b.created_at || 0).getTime();
    const aTime = new Date(a.run_time_et || a.created_at || 0).getTime();
    return bTime - aTime;
  });

const snapshot =
  sortedRows.find(isUsableUsdSnapshot) ||
  sortedRows[0];

if (!snapshot) {
  throw new Error("No valid market snapshot found");
}

const quality = parseQuality(snapshot);

const missingInputs = [];
const selectedInputWarnings = [];

function requireInput(key, label = key) {
  const value = snapshot[key];
  if (!hasValue(value)) {
    missingInputs.push(label);
    return null;
  }
  return value;
}

const goldD5 = hasValue(snapshot.gold_d5_pct)
  ? snapshot.gold_d5_pct
  : snapshot.gold_d1_pct;

if (!hasValue(snapshot.gold_d5_pct) && hasValue(snapshot.gold_d1_pct)) {
  selectedInputWarnings.push("gold_d5_pct missing; using gold_d1_pct fallback");
}

const nqD5 = hasValue(snapshot.nq_d5_pct)
  ? snapshot.nq_d5_pct
  : snapshot.nq_d1_pct;

if (!hasValue(snapshot.nq_d5_pct) && hasValue(snapshot.nq_d1_pct)) {
  selectedInputWarnings.push("nq_d5_pct missing; using nq_d1_pct fallback");
}

const selectedBy = isUsableUsdSnapshot(snapshot)
  ? "latest_usd_usable_snapshot"
  : "latest_available_snapshot_fallback";

const debugTopRows = sortedRows.slice(0, 5).map((r, index) => ({
  rank: index + 1,
  id: r.id,
  created_at: r.created_at,
  run_time_et: r.run_time_et,
  snapshot_date: r.snapshot_date,
  source_status: r.source_status,
  collector_version: r.collector_version,
  vix_level: r.vix_level,
  dxy_level: r.dxy_level,
  de_2y_yield: r.de_2y_yield,
  us_de_2y_spread: r.us_de_2y_spread,
  us_de_2y_spread_d5_bps: r.us_de_2y_spread_d5_bps,
  fed_bias: r.fed_bias,
  usd_usable: isUsableUsdSnapshot(r)
}));

const usdInputPack = {
  agent_name: "USD",
  layer: 1,
  isolation_rule: "This Layer 1 agent may only use this market snapshot. It must not read other agent outputs.",
  execution_question: "Based on confirmed value-driving factors available at execution time, what is the likely direction of USD?",

  snapshot_id: snapshot.id,
  snapshot_date: snapshot.snapshot_date,
  run_time_et: snapshot.run_time_et,
  created_at: snapshot.created_at || null,
  collector_version: snapshot.collector_version || null,
  source_status: snapshot.source_status || null,
  data_quality: quality,

  snapshot_selection: {
    selected_snapshot_id: snapshot.id,
    selected_run_time_et: snapshot.run_time_et,
    selected_created_at: snapshot.created_at || null,
    selected_snapshot_date: snapshot.snapshot_date,
    selected_from_rows: rows.length,
    selected_by: selectedBy,
    missing_required_inputs_for_usd: missingInputs,
    warnings: selectedInputWarnings,
    top_5_rows_seen_by_workflow: debugTopRows
  },

  available_inputs: {
    vix_level: requireInput("vix_level"),
    vix_d1: snapshot.vix_d1 ?? null,
    vix_d5: snapshot.vix_d5 ?? null,

    dxy_level: requireInput("dxy_level"),
    dxy_d1: requireInput("dxy_d1"),
    dxy_d5: requireInput("dxy_d5"),
    dxy_d20: snapshot.dxy_d20 ?? null,

    us_2y_yield: requireInput("us_2y_yield"),
    us_2y_d5_bps: requireInput("us_2y_d5_bps"),
    us_2y_d20_bps: snapshot.us_2y_d20_bps ?? null,

    de_2y_yield: requireInput("de_2y_yield"),
    de_2y_d5_bps: snapshot.de_2y_d5_bps ?? null,
    de_2y_d20_bps: snapshot.de_2y_d20_bps ?? null,

    us_de_2y_spread: requireInput("us_de_2y_spread"),
    us_de_2y_spread_d1_bps: snapshot.us_de_2y_spread_d1_bps ?? null,
    us_de_2y_spread_d5_bps: requireInput("us_de_2y_spread_d5_bps"),
    us_de_2y_spread_d20_bps: snapshot.us_de_2y_spread_d20_bps ?? null,

    us_10y_yield: snapshot.us_10y_yield ?? null,
    us_10y_d5_bps: snapshot.us_10y_d5_bps ?? null,
    us_10y_d20_bps: snapshot.us_10y_d20_bps ?? null,

    us_10y_real_yield: requireInput("us_10y_real_yield"),
    us_10y_real_yield_d5_bps: requireInput("us_10y_real_yield_d5_bps"),
    us_10y_real_yield_d20_bps: snapshot.us_10y_real_yield_d20_bps ?? null,

    gold_price: snapshot.gold_price ?? null,
    gold_d1_pct: requireInput("gold_d1_pct"),
    gold_d5_pct: goldD5,
    gold_d20_pct: snapshot.gold_d20_pct ?? null,

    nq_price: snapshot.nq_price ?? null,
    nq_d1_pct: requireInput("nq_d1_pct"),
    nq_d5_pct: nqD5,
    nq_d20_pct: snapshot.nq_d20_pct ?? null,

    btc_price: snapshot.btc_price ?? null,
    btc_d1_pct: snapshot.btc_d1_pct ?? null,
    btc_d5_pct: snapshot.btc_d5_pct ?? null,
    btc_d20_pct: snapshot.btc_d20_pct ?? null,

    latest_us_event: snapshot.latest_us_event ?? null,
    upcoming_events: snapshot.upcoming_events ?? null,
    fed_bias: requireInput("fed_bias"),
    equities_regime: snapshot.equities_regime ?? null
  },

  missing_inputs_must_be_scored_neutral: [
    "de_2y_yield if unavailable",
    "us_de_2y_spread if unavailable",
    "us_de_2y_spread_d5_bps if unavailable",
    "latest_us_event if unavailable",
    "fed_bias if unavailable",
    "gold_d5_pct if unavailable",
    "nq_d1_pct if unavailable",
    "equities_regime if unavailable"
  ]
};

return [{ json: usdInputPack }];

const logicItem = $('Get USD Logic Document').first().json;
const marketItem = $('Build USD Input Pack').first().json;

let logicDocument = logicItem.content || '';

if (logicItem.encoding === 'base64') {
  logicDocument = Buffer.from(logicDocument, 'base64').toString('utf8');
}

return [
  {
    json: {
      logic_document: logicDocument,
      market_snapshot: marketItem
    }
  }
];

const openAiItem = $input.first().json;

let text =
  openAiItem.output?.[0]?.content?.[0]?.text ||
  openAiItem.text ||
  openAiItem.message ||
  '';

if (!text) {
  throw new Error('No OpenAI text output found');
}

let report;
try {
  report = JSON.parse(text);
} catch (error) {
  throw new Error(`OpenAI returned invalid JSON: ${error.message}. Raw text: ${text.slice(0, 1000)}`);
}

const marketSnapshot = $('Combine md & market snapshot').first().json.market_snapshot || {};
const marketInputs = marketSnapshot.available_inputs || {};

function pct(value) {
  if (value === null || value === undefined || value === '') return null;
  const match = String(value).match(/(\d+(\.\d+)?)/);
  return match ? Number(match[1]) : null;
}

function reasonFor(tf) {
  return (
    report[`${tf}_reason`] ||
    report.reasoning_summary ||
    ''
  );
}

function hasValue(v) {
  return v !== null && v !== undefined && v !== '';
}

function inputWarning(key, label) {
  return hasValue(marketInputs[key]) ? null : `Missing ${label}`;
}

const deterministicInputWarnings = [
  inputWarning('de_2y_yield', 'Germany 2Y yield'),
  inputWarning('us_de_2y_spread', 'US-DE 2Y spread'),
  inputWarning('us_de_2y_spread_d5_bps', 'US-DE 2Y spread 5d bps'),
  inputWarning('fed_bias', 'Fed bias'),
  inputWarning('latest_us_event', 'latest US event')
].filter(Boolean);

return [
  {
    json: {
      snapshot_id: marketSnapshot.snapshot_id || null,
      agent_name: 'USD',
      layer: 1,
      run_time_et: marketSnapshot.run_time_et || new Date().toISOString(),
      snapshot_date: marketSnapshot.snapshot_date || new Date().toISOString().slice(0, 10),

      market_inputs: marketInputs,
      snapshot_selection: marketSnapshot.snapshot_selection || null,

      model_reported_warnings: report.risk_flags || report.warnings || [],
      input_validation_warnings: deterministicInputWarnings,

      call_24h_direction: report.direction_24h || null,
      call_24h_conviction: pct(report.conviction_24h),
      call_24h_reason: reasonFor('24h'),

      call_3d_direction: report.direction_3_day || null,
      call_3d_conviction: pct(report.conviction_3_day),
      call_3d_reason: reasonFor('3d'),

      call_current_week_direction: report.direction_current_week || null,
      call_current_week_conviction: pct(report.conviction_current_week),
      call_current_week_reason: reasonFor('current_week'),

      call_next_week_direction: report.direction_next_week || null,
      call_next_week_conviction: pct(report.conviction_next_week),
      call_next_week_reason: reasonFor('next_week'),

      call_current_month_direction: report.direction_current_month || null,
      call_current_month_conviction: pct(report.conviction_current_month),
      call_current_month_reason: reasonFor('current_month'),

      direction_24h: report.direction_24h || null,
      conviction_24h: pct(report.conviction_24h),
      direction_3_day: report.direction_3_day || null,
      conviction_3_day: pct(report.conviction_3_day),
      direction_current_week: report.direction_current_week || null,
      conviction_current_week: pct(report.conviction_current_week),
      direction_next_week: report.direction_next_week || null,
      conviction_next_week: pct(report.conviction_next_week),
      direction_current_month: report.direction_current_month || null,
      conviction_current_month: pct(report.conviction_current_month),

      factor_breakdown: report.factor_breakdown || {},

      // Keep the old dashboard field, but make it deterministic, not model hallucination
      warnings: deterministicInputWarnings,

      full_output: {
        ...report,
        model_reported_warnings: report.risk_flags || report.warnings || [],
        input_validation_warnings: deterministicInputWarnings,
        market_inputs_seen_by_workflow: marketInputs,
        snapshot_selection: marketSnapshot.snapshot_selection || null
      },

      raw_agent_output: report,

      logic_document: 'agent_usd_direction.md',
      logic_document_version: report.logic_document_version || 'v2_basic_engine',
      reasoning_summary: report.reasoning_summary || '',

      score_bullish: report.score_bullish ?? null,
      score_bearish: report.score_bearish ?? null,
      score_neutral: report.score_neutral ?? null
    }
  }
];

const item = $input.first().json;
const inputs = item.market_inputs || {};

function n(v) {
  const x = Number(v);
  return Number.isFinite(x) ? x : null;
}

function makeFactor(signal, evidence, reason) {
  return { signal, evidence, reason };
}

function signalFromDelta(value, upThreshold, downThreshold, bullishReason, bearishReason, neutralReason, label) {
  const d = n(value);
  if (d === null) return makeFactor("NEUTRAL", `Missing ${label}`, "Missing input");
  if (d >= upThreshold) return makeFactor("BULLISH", `${label} ${d}`, bullishReason);
  if (d <= downThreshold) return makeFactor("BEARISH", `${label} ${d}`, bearishReason);
  return makeFactor("NEUTRAL", `${label} ${d}`, neutralReason);
}

const TIMEFRAME_WEIGHTS = {
  "24h": {
  F1: 10, F2: 14, F3: 10, F4: 10, F5: 14,
  F6: 4, F7: 24, F8: 12, F9: 1, F10: 1
},
  "3d": {
    F1: 8, F2: 16, F3: 16, F4: 16, F5: 14,
    F6: 8, F7: 8, F8: 10, F9: 3, F10: 1
  },
  "current_week": {
    F1: 5, F2: 14, F3: 18, F4: 18, F5: 15,
    F6: 7, F7: 5, F8: 12, F9: 5, F10: 1
  },
  "next_week": {
    F1: 4, F2: 12, F3: 20, F4: 18, F5: 6,
    F6: 5, F7: 6, F8: 18, F9: 10, F10: 1
  },
  "current_month": {
    F1: 3, F2: 12, F3: 18, F4: 20, F5: 8,
    F6: 5, F7: 5, F8: 18, F9: 10, F10: 1
  }
};

function factorSignals(tf) {
  const vix = n(inputs.vix_level);
  const fed = String(inputs.fed_bias || "").toLowerCase();

  const use20d = tf === "current_month" || tf === "next_week";
  const useWeek = tf === "current_week";

  const us2yDelta = use20d && n(inputs.us_2y_d20_bps) !== null
    ? inputs.us_2y_d20_bps
    : inputs.us_2y_d5_bps;

  const realYieldDelta = use20d && n(inputs.us_10y_real_yield_d20_bps) !== null
    ? inputs.us_10y_real_yield_d20_bps
    : inputs.us_10y_real_yield_d5_bps;

  const dxyDelta = use20d && n(inputs.dxy_d20) !== null
    ? inputs.dxy_d20
    : tf === "24h" && n(inputs.dxy_d1) !== null
      ? inputs.dxy_d1
      : inputs.dxy_d5;

  const goldDelta = use20d && n(inputs.gold_d20_pct) !== null
    ? inputs.gold_d20_pct
    : inputs.gold_d5_pct;

  const nqDelta = tf === "24h" && n(inputs.nq_d1_pct) !== null
    ? inputs.nq_d1_pct
    : inputs.nq_d5_pct;

  const signals = {};

  signals.F1 = (() => {
    if (vix === null) return makeFactor("NEUTRAL", "Missing VIX", "Missing input");
    if (vix > 25) return makeFactor("BULLISH", `VIX ${vix}`, "Safe-haven USD demand active");
    if (vix < 16) return makeFactor("BEARISH", `VIX ${vix}`, "Risk-on rotation away from USD");
    return makeFactor("NEUTRAL", `VIX ${vix}`, "Domestic drivers dominate");
  })();

  signals.F2 = signalFromDelta(
    us2yDelta,
    5,
    -5,
    "US front-end yields support USD",
    "US front-end yields pressure USD",
    "Move below threshold",
    use20d ? "US 2Y 20d bps" : "US 2Y 5d bps"
  );

  signals.F3 = signalFromDelta(
    inputs.us_de_2y_spread_d5_bps,
    5,
    -5,
    "Relative rates support USD",
    "Relative rates weaken USD",
    "Move below threshold",
    "US-DE 2Y spread 5d bps"
  );

  signals.F4 = signalFromDelta(
    realYieldDelta,
    5,
    -5,
    "Rising real yields support USD",
    "Falling real yields pressure USD",
    "Move below threshold",
    use20d ? "Real yield 20d bps" : "Real yield 5d bps"
  );

  signals.F5 = signalFromDelta(
    dxyDelta,
    tf === "24h" ? 0.15 : 0.3,
    tf === "24h" ? -0.15 : -0.3,
    "DXY confirms USD strength",
    "DXY confirms USD weakness",
    "Move below threshold",
    use20d ? "DXY 20d %" : tf === "24h" ? "DXY 1d %" : "DXY 5d %"
  );

  signals.F6 = (() => {
    const d = n(goldDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing gold delta", "Missing input");
    if (d < -0.1) return makeFactor("BULLISH", `Gold ${d}%`, "Gold weakness supports USD");
    if (d > 0.1) return makeFactor("BEARISH", `Gold ${d}%`, "Gold strength pressures USD");
    return makeFactor("NEUTRAL", `Gold ${d}%`, "Gold flat");
  })();

  signals.F7 = (() => {
  const ev = inputs.latest_us_event;

  if (!ev) {
    return makeFactor("NEUTRAL", "No recent US event", "No confirmed surprise");
  }

  if (ev.usd_signal === "BULLISH") {
    return makeFactor("BULLISH", ev.event || JSON.stringify(ev), "Positive US surprise supports USD");
  }

  if (ev.usd_signal === "BEARISH") {
    return makeFactor("BEARISH", ev.event || JSON.stringify(ev), "Negative US surprise pressures USD");
  }

  return makeFactor("NEUTRAL", ev.event || JSON.stringify(ev), "No clear USD surprise");
})();

  signals.F8 = (() => {
    if (!fed || fed === "unknown") return makeFactor("NEUTRAL", "Fed bias unknown", "Missing input");
    if (fed.includes("hawkish")) return makeFactor("BULLISH", `Fed bias ${fed}`, "Hawkish Fed supports USD");
    if (fed.includes("dovish")) return makeFactor("BEARISH", `Fed bias ${fed}`, "Dovish Fed pressures USD");
    return makeFactor("NEUTRAL", `Fed bias ${fed}`, "No clear Fed impulse");
  })();

  signals.F9 = (() => {
    if (vix !== null && vix > 25) return makeFactor("BULLISH", `VIX ${vix}`, "Dollar Smile right-side safe-haven bid");
    if (vix !== null && vix < 16 && !fed.includes("hawkish")) {
      return makeFactor("BEARISH", `VIX ${vix}`, "Risk-on Dollar Smile bottom weakens USD");
    }
    return makeFactor("NEUTRAL", "No clear Dollar Smile edge", "Insufficient regime evidence");
  })();

  signals.F10 = (() => {
    const nq = n(nqDelta);
    if (nq === null || vix === null) return makeFactor("NEUTRAL", "Missing NQ/VIX", "Missing input");
    if (vix < 16 && nq > 0) return makeFactor("BEARISH", `NQ ${nq}% risk-on`, "Risk appetite reduces USD demand");
    if (vix < 16 && nq < 0) return makeFactor("BULLISH", `NQ ${nq}% risk-on`, "Equity weakness supports USD");
    if (vix > 25 && nq < 0) return makeFactor("BULLISH", `NQ ${nq}% risk-off`, "Risk-off supports USD");
    return makeFactor("NEUTRAL", `NQ ${nq}%, VIX ${vix}`, "No clear equity/USD signal");
  })();

  return signals;
}

function scoreTimeframe(tf) {
  const weights = TIMEFRAME_WEIGHTS[tf];
  const signals = factorSignals(tf);

  let bullish = 0;
  let bearish = 0;
  let neutral = 0;

  let bullishCount = 0;
  let bearishCount = 0;
  let neutralCount = 0;

  const factorBreakdown = {};

  for (const [id, sig] of Object.entries(signals)) {
    const weight = weights[id] || 0;

    factorBreakdown[id] = {
      ...sig,
      weight
    };

    if (sig.signal === "BULLISH") {
      bullish += weight;
      bullishCount++;
    } else if (sig.signal === "BEARISH") {
      bearish += weight;
      bearishCount++;
    } else {
      neutral += weight;
      neutralCount++;
    }
  }

  const active = bullish + bearish;
  const bullishArgument = active > 0 ? Math.round((bullish / active) * 100) : 0;
  const bearishArgument = active > 0 ? Math.round((bearish / active) * 100) : 0;
  const neutralPct = Math.round(neutral);

  const netEdge = bullishArgument - bearishArgument;

  const baseDirection =
    bullish > bearish
      ? "BULLISH"
      : bearish > bullish
        ? "BEARISH"
        : "NO_CLEAR_BIAS";

  const absEdge = Math.abs(netEdge);

  const direction =
    baseDirection === "NO_CLEAR_BIAS"
      ? "NO_CLEAR_BIAS"
      : absEdge < 20
        ? `${baseDirection}_LEAN`
        : baseDirection;

  const conviction =
    baseDirection === "BULLISH"
      ? bullishArgument
      : baseDirection === "BEARISH"
        ? bearishArgument
        : 0;

  const strength =
    absEdge >= 40 ? "VERY_STRONG" :
    absEdge >= 25 ? "STRONG" :
    absEdge >= 15 ? "MODERATE" :
    "WEAK";

  const reason = `${tf} deterministic score: bullish argument ${bullishArgument}%, bearish argument ${bearishArgument}%, neutral/inactive ${neutralPct}%, net edge ${netEdge > 0 ? "+" : ""}${netEdge} ${baseDirection.toLowerCase().replace("_", " ")}.`;

  return {
    direction,
    conviction,
    reason,
    factor_breakdown: factorBreakdown,
    score_bullish: bullishCount,
    score_bearish: bearishCount,
    score_neutral: neutralCount,
    weighted_score: {
      bullish_weight: bullish,
      bearish_weight: bearish,
      neutral_weight: neutral,
      active_weight: active,
      weight_margin: Math.abs(bullish - bearish)
    },
    conviction_model: {
      bullish_argument_pct: bullishArgument,
      bearish_argument_pct: bearishArgument,
      neutral_pct: neutralPct,
      active_participation_pct: active,
      net_edge_pct: netEdge,
      final_conviction: conviction,
      verdict_strength: strength,
      final_conviction_logic: reason,

      // legacy aliases for current dashboard
      weighted_edge: Math.abs(netEdge) / 100,
      raw_conviction: conviction,
      base_conviction: conviction,
      participation: active,
      participation_cap: active,
      conflict_penalty: 0,
      missing_input_penalty: 0,
      agreement_boost: 0
    }
  };
}

const r24h = scoreTimeframe("24h");
const r3d = scoreTimeframe("3d");
const rWeek = scoreTimeframe("current_week");
const rNextWeek = scoreTimeframe("next_week");
const rMonth = scoreTimeframe("current_month");

const output = {
  ...(item.full_output || {}),

  direction_24h: r24h.direction,
  conviction_24h: r24h.conviction,
  reason_24h: r24h.reason,

  direction_3_day: r3d.direction,
  conviction_3_day: r3d.conviction,
  reason_3_day: r3d.reason,

  direction_current_week: rWeek.direction,
  conviction_current_week: rWeek.conviction,
  reason_current_week: rWeek.reason,

  direction_next_week: rNextWeek.direction,
  conviction_next_week: rNextWeek.conviction,
  reason_next_week: rNextWeek.reason,

  direction_current_month: rMonth.direction,
  conviction_current_month: rMonth.conviction,
  reason_current_month: rMonth.reason,

  weighted_score: r24h.weighted_score,
  conviction_model: r24h.conviction_model,
  factor_breakdown: r24h.factor_breakdown,

  timeframe_models: {
    "24h": r24h,
    "3d": r3d,
    "current_week": rWeek,
    "next_week": rNextWeek,
    "current_month": rMonth
  },

  score_bullish: r24h.score_bullish,
  score_bearish: r24h.score_bearish,
  score_neutral: r24h.score_neutral,

  reasoning_summary: `USD weighted verdicts calculated deterministically by timeframe. 24h ${r24h.direction} ${r24h.conviction}%, 3d ${r3d.direction} ${r3d.conviction}%, current week ${rWeek.direction} ${rWeek.conviction}%, next week ${rNextWeek.direction} ${rNextWeek.conviction}%, current month ${rMonth.direction} ${rMonth.conviction}%.`
};

const {
  market_inputs,
  input_validation_warnings,
  model_reported_warnings,
  snapshot_selection,
  ...safeItem
} = item;

return [{
  json: {
    ...safeItem,

    call_24h_direction: output.direction_24h,
